import{_ as t,o as e,c as i,a2 as n}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"AI 笔记","description":"","frontmatter":{"title":"AI 笔记","date":"2026-07-04T00:00:00.000Z","tags":["AI","LLM"]},"headers":[],"relativePath":"AI/AI笔记.md","filePath":"AI/AI笔记.md","lastUpdated":null}'),l={name:"AI/AI笔记.md"};function r(s,a,o,h,d,c){return e(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="ai-笔记" tabindex="-1">AI 笔记 <a class="header-anchor" href="#ai-笔记" aria-label="Permalink to &quot;AI 笔记&quot;">​</a></h1><h2 id="什么是-rag" tabindex="-1">什么是 RAG？ <a class="header-anchor" href="#什么是-rag" aria-label="Permalink to &quot;什么是 RAG？&quot;">​</a></h2><p>RAG（Retrieval-Augmented Generation）是一种将检索与生成结合的技术。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户提问 → 检索相关文档 → 拼接 Prompt → LLM 生成回答</span></span></code></pre></div><h3 id="核心流程" tabindex="-1">核心流程 <a class="header-anchor" href="#核心流程" aria-label="Permalink to &quot;核心流程&quot;">​</a></h3><ol><li><strong>文档切分</strong>：将文档切分成合适大小的 chunks</li><li><strong>向量化</strong>：用 Embedding 模型将 chunks 转为向量</li><li><strong>存入向量库</strong>：如 Milvus、Qdrant、Chroma</li><li><strong>检索</strong>：将用户问题向量化，在向量库中找最相似的 chunks</li><li><strong>生成</strong>：将检索到的 chunks 作为上下文，交给 LLM 生成回答</li></ol><h2 id="langchain-简介" tabindex="-1">LangChain 简介 <a class="header-anchor" href="#langchain-简介" aria-label="Permalink to &quot;LangChain 简介&quot;">​</a></h2><p>LangChain 是一个构建 LLM 应用的框架，提供：</p><ul><li>Prompt 管理</li><li>链式调用</li><li>Agent 机制</li><li>记忆功能</li><li>工具调用</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><p>后续会持续补充更多 AI 相关的学习笔记。</p>',11)])])}const g=t(l,[["render",r]]);export{u as __pageData,g as default};
